Class CSVBuilder Extends %RegisteredObject
{
    /// Build CSV string from list of values
    ClassMethod BuildCSV(values As %ListOfDataTypes) As %String
    {
        Set result = ""
        // BUGGY: Inefficient - creates new string each iteration
        // For large lists this is O(n^2)
        For i=1:1:values.Count() {
            If (i > 1) {
                Set result = result _ ","
            }
            Set result = result _ values.GetAt(i)
        }
        Quit result
    }
}

