Class TestCSVBuilder Extends %RegisteredObject
{
    ClassMethod TestBuildCSV()
    {
        // Small list test
        Set small = ##class(%ListOfDataTypes).%New()
        Do small.Insert("a")
        Do small.Insert("b")
        Do small.Insert("c")
        Set result = ##class(CSVBuilder).BuildCSV(small)
        If (result '= "a,b,c") {
            Throw ##class(%Exception.General).%New("Small CSV failed: got "_result)
        }

        // Performance test - should complete quickly even for larger lists
        Set large = ##class(%ListOfDataTypes).%New()
        For i=1:1:1000 {
            Do large.Insert("item"_i)
        }
        Set start = $ZH
        Set result = ##class(CSVBuilder).BuildCSV(large)
        Set elapsed = $ZH - start

        // Should complete in under 1 second (generous limit)
        If (elapsed > 1) {
            Throw ##class(%Exception.General).%New("BuildCSV too slow: "_elapsed_" seconds")
        }

        // Verify result starts and ends correctly
        If (result '[ "item1,") {
            Throw ##class(%Exception.General).%New("Large CSV doesn't start with item1")
        }
        If (result '[ ",item1000") {
            Throw ##class(%Exception.General).%New("Large CSV doesn't end with item1000")
        }
    }
}
